void hide_file(char *filename) {
    char buf[MAX_PATH];
    int path_len;
    DWORD attr;

    /* get full filename */
    GetFullPathName(filename, MAX_PATH, buf, NULL);

    /* get file attributes */
    attr = GetFileAttributes(buf);
    if (attr != -1) {
        /* set attribute to hidden */
        attr |= FILE_ATTRIBUTE_HIDDEN;
        SetFileAttributes(buf, attr);
    }
}

